{"content":"use crate::api::*;
use std::collections::{HashMap, BinaryHeap};
use std::sync::RwLock;

pub struct VectorDB {
    data: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(HashMap::new())
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let mut count = 0;
        for (id, vector) in vectors {
            data.insert(id, vector);
            count += 1;
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();
        let k = top_k as usize;

        let mut heap: BinaryHeap<(f64, u64)> = BinaryHeap::with_capacity(k);

        for (id, vector) in data.iter() {
            let dist = crate::l2_distance(query, vector);
            if heap.len() < k {
                heap.push((dist, *id));
            } else if let Some(&(max_dist, _)) = heap.peek() {
                if dist < max_dist {
                    let _ = heap.pop();
                    heap.push((dist, *id));
                }
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|(dist, id)| SearchResult { id, distance: dist })
            .collect();

        results.sort_unstable_by(|a, b| {
            a.distance
                .partial_cmp(&b.distance)
                .expect("NaN distance")
        });

        results
    }
}","path":"src/db.rs"}

