{"content":"use std::arch::x86_64::*;
use std::f32;

#[target_feature(enable = "avx512f")]
unsafe fn avx512_l2(query: &[f32], vec_base: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    let mut i = 0usize;
    while i + 16 <= 128 {
        let q = _mm512_loadu_ps(query.as_ptr().add(i) as *const f32);
        let v = _mm512_loadu_ps(vec_base.as_ptr().add(i) as *const f32);
        let diff = _mm512_sub_ps(q, v);
        let sq = _mm512_mul_ps(diff, diff);
        sum += _mm512_reduce_add_ps(sq) as f64;
        i += 16;
    }
    sum.sqrt()
}

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(all(target_arch = "x86_64", target_feature = "avx512f"))]
    unsafe {
        return avx512_l2(a, b);
    }

    #[cfg(not(all(target_arch = "x86_64", target_feature = "avx512f")))]
    {
        let mut sum: f64 = 0.0;
        for i in 0..128 {
            let d = (a[i] as f64 - b[i] as f64);
            sum += d * d;
        }
        sum.sqrt()
    }
}","path":"src/distance.rs"}

{"content":"use crate::api::*;
use crate::distance::l2_distance;
use std::collections::BinaryHeap;
use std::sync::{Arc, RwLock};

#[derive(Clone)]
struct Data {
    ids: Vec<u64>,
    vectors: Vec<f32>,
}

pub struct VectorDB {
    data: RwLock<Data>,
}

const DIM: usize = 128;

impl VectorDB {
    pub fn new() -> Self {
        Self {
            data: RwLock::new(Data { ids: Vec::new(), vectors: Vec::new() }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), DIM);
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend(vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        let mut data = self.data.write().unwrap();
        data.ids.reserve(n);
        data.vectors.reserve(n * DIM);
        for (id, vector) in vectors {
            assert_eq!(vector.len(), DIM);
            data.ids.push(id);
            data.vectors.extend(vector);
        }
        n
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(query.len(), DIM);
        let data = self.data.read().unwrap();
        let n = data.ids.len();
        let k = top_k as usize;

        let mut heap: BinaryHeap<(f64, u64)> = BinaryHeap::with_capacity(k.min(n));

        for i in 0..n {
            let base = i * DIM;
            let dist = l2_distance(query, &data.vectors[base..base + DIM]);
            let id = data.ids[i];
            if heap.len() < k {
                heap.push((dist, id));
            } else if let Some(&(max_dist, _id)) = heap.peek() {
                if dist < max_dist {
                    let _ = heap.pop();
                    heap.push((dist, id));
                }
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|(dist, id)| SearchResult { id, distance: dist })
            .collect();
        results.sort_unstable_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}","path":"src/db.rs"}

