            data: RwLock::new(Data {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        assert_eq!(vector.len(), DIM);
        let mut data = self.data.write().unwrap();
        data.ids.push(id);
        data.vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let n = vectors.len();
        let mut data = self.data.write().unwrap();
        data.ids.reserve(n);
        data.vectors.reserve(n * DIM);
        for (id, vector) in vectors {
            assert_eq!(vector.len(), DIM);
            data.ids.push(id);
            data.vectors.extend_from_slice(&vector);
        }
        n
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(query.len(), DIM);
        let data = self.data.read().unwrap();
        let n = data.ids.len();
        let k = top_k as usize;

        let mut heap: BinaryHeap<Candidate> = BinaryHeap::with_capacity(k.min(n));

        for i in 0..n {
            let base = i * DIM;
            let vec_slice = &data.vectors[base..base + DIM];
            let dist = l2_distance(query, vec_slice);
            let cand = Candidate { dist, id: data.ids[i] };

            if heap.len() < k {
                heap.push(cand);
            } else if let Some(top) = heap.peek() {
                if cand.dist < top.dist {
                    let _ = heap.pop();
                    heap.push(cand);
                }
            }
