pub fn l2_dist_sq(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    debug_assert_eq!(a.len(), super::DIM);
    let mut sum: f64 = 0.0;
    let al = a.as_ptr();
    let bl = b.as_ptr();
    let mut i = 0isize;
    while i < 128 {
        let da = unsafe { *al.offset(i) as f64 };
        let db = unsafe { *bl.offset(i) as f64 };
        sum += (da - db) * (da - db);
        i += 1;
    }
    sum
}

